// ── Topic Tests v2 — content catalog ─────────────────────────────────────────
// Source of truth for topic/misconception/question/distractor content.
// Reviewed and versioned here, then pushed to Supabase via `npm run seed:topictests`
// (scripts/seedTopicTests.ts) — an idempotent upsert, not a one-shot migration.
// Edit this file to add/change content, then re-run the seed script.

export type Difficulty = 'foundational' | 'application' | 'extension';

export interface CatalogMisconception {
  code: string;          // stable slug, referenced by distractors below
  label: string;
  description: string;
}

export interface CatalogOption {
  key: string;            // 'A' | 'B' | 'C' | 'D' ...
  text: string;
}

export interface CatalogDistractor {
  optionKey: string;              // must match a key in the question's options
  misconceptionCode: string;      // must match a code in the topic's misconceptions
  cognitiveErrorType: 'procedural' | 'conceptual' | 'overgeneralisation';
  severityWeight: number;         // 0–1, how much this error should weigh in intervention flags
  explanation: string;            // shown to student on review
}

export interface CatalogQuestion {
  questionType: 'mcq' | 'short_answer';
  prompt: string;
  difficulty: Difficulty;
  options?: CatalogOption[];      // mcq only
  correctAnswer: string;          // option key (mcq) or exact/tolerance value (short_answer)
  answerTolerance?: number;       // short_answer only
  distractors?: CatalogDistractor[]; // mcq only
}

export interface CatalogTopic {
  topicKey: string;       // stable slug, matches `topics.topic_key`
  label: string;
  subjectCode: string;    // matches `subjects.code`
  grade: number;
  term: number;
  misconceptions: CatalogMisconception[];
  questions: CatalogQuestion[];
}

